SELECT supplier_name 
FROM suppliers 
WHERE lead_time > (SELECT AVG(lead_time) FROM suppliers);

SELECT T1.name AS component_name, T2.supplier_name
FROM components AS T1
INNER JOIN suppliers AS T2 ON T1.supplier_id = T2.supplier_id;

SELECT name
FROM components
ORDER BY criticality ASC;

SELECT supplier_name
FROM suppliers
WHERE quality_rating IS NULL AND reliability_rating IS NULL;

SELECT name 
FROM components 
WHERE min_stock_level > (SELECT AVG(min_stock_level) FROM components);
